import torch.nn.functional as F

def next_token(logits, T=1.0, top_k=0, top_p=1.0):
    logits = logits / T
    if top_k:
        kth = torch.topk(logits, top_k).values[..., -1, None]
        logits[logits < kth] = float("-inf")
    probs = F.softmax(logits, dim=-1)
    if top_p < 1.0:
        s, idx = torch.sort(probs, descending=True)
        mask = torch.cumsum(s, -1) - s > top_p
        s[mask] = 0
        probs = torch.zeros_like(probs).scatter(-1, idx, s)
    return torch.multinomial(probs / probs.sum(), 1)

def gen(client, messages, mode="chat"):
    cfg = {
        "json":  dict(temperature=0.0, top_p=1.0, seed=0),
        "chat":  dict(temperature=0.7, top_p=0.9),
        "ideas": dict(temperature=1.0, top_p=0.95),
    }[mode]
    return client.chat.completions.create(
        model="gpt-4o-mini", messages=messages, **cfg)

